@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @bind="searchText"
           @bind:event="oninput"
           @bind:after="OnSearchTextChanged" />

    @if (isLoading)
    {
        <div class="product-search-status">Searching…</div>
    }
    else if (errorMessage is not null)
    {
        <div class="product-search-error">
            <span>@errorMessage</span>
            <button @onclick="RetrySearch">Retry</button>
        </div>
    }
    else if (products is not null)
    {
        if (products.Count == 0)
        {
            <div class="product-search-status">No products found.</div>
        }
        else
        {
            <div class="product-search-results">
                @foreach (var product in products)
                {
                    <div class="product-card" @onclick="() => OnProductSelected.InvokeAsync(product)">
                        <img src="@product.ImageUrl" alt="@product.Name" loading="lazy" />
                        <div class="product-card-body">
                            <h3>@product.Name</h3>
                            <p>@product.Price.ToString("C")</p>
                        </div>
                    </div>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string searchText = string.Empty;
    private List<Product>? products;
    private bool isLoading;
    private string? errorMessage;

    private Timer? debounceTimer;
    private CancellationTokenSource? searchCts;
    private bool disposed;

    private async Task OnSearchTextChanged()
    {
        errorMessage = null;
        debounceTimer?.Dispose();

        var query = searchText.Trim();
        if (string.IsNullOrEmpty(query))
        {
            CancelInflightSearch();
            products = null;
            isLoading = false;
            return;
        }

        debounceTimer = new Timer(_ =>
        {
            _ = InvokeAsync(() => ExecuteSearchAsync(query));
        }, null, 300, Timeout.Infinite);
    }

    private async Task ExecuteSearchAsync(string query)
    {
        CancelInflightSearch();

        var cts = new CancellationTokenSource();
        searchCts = cts;

        isLoading = true;
        errorMessage = null;
        StateHasChanged();

        try
        {
            var results = await ProductService.SearchAsync(query, cts.Token);

            if (cts.Token.IsCancellationRequested)
                return;

            products = results;
            errorMessage = null;
        }
        catch (OperationCanceledException)
        {
            // Search was superseded or component disposed; discard silently.
        }
        catch (Exception)
        {
            if (!cts.Token.IsCancellationRequested)
            {
                products = null;
                errorMessage = "Something went wrong. Please try again.";
            }
        }
        finally
        {
            if (!cts.Token.IsCancellationRequested)
            {
                isLoading = false;
                StateHasChanged();
            }
        }
    }

    private async Task RetrySearch()
    {
        var query = searchText.Trim();
        if (!string.IsNullOrEmpty(query))
        {
            await ExecuteSearchAsync(query);
        }
    }

    private void CancelInflightSearch()
    {
        searchCts?.Cancel();
        searchCts?.Dispose();
        searchCts = null;
    }

    public void Dispose()
    {
        disposed = true;
        debounceTimer?.Dispose();
        CancelInflightSearch();
    }
}

